"""TCP-чат: клиент для PowerShell с компактным выводом и защитой от спама в консоли."""

from __future__ import annotations

import argparse
import os
import re
import socket
import sys
import textwrap
import threading
import time
from enum import Enum, auto
from typing import TextIO

# --- конфигурация ---

DEFAULT_HOST = "10.1.124.59"
DEFAULT_PORT = 12345
ENCODING = "utf-8"
RECV_CHUNK = 4096
MAX_NICK_LEN = 32
DISPLAY_BODY_MAX = 72
DISPLAY_OTHER_MAX = 200
TERMINAL_WIDTH = 78
HELP_BURST_SEC = 0.15
BLOCK_MAGIC = "@@BLOCK@@"
BLOCK_SEP = "\x1f"

QUIT_COMMANDS = frozenset({"/quit", "/exit"})
LOCAL_COMMANDS = frozenset({"/clear"})
KNOWN_COMMANDS = frozenset({"help", "active", "users", "quit", "exit"})
COMMAND_TYPOS = {"uses": "/users", "user": "/users", "halp": "/help"}

CHAT_RE = re.compile(r"^\[(\d{2}:\d{2})\] (.+?): (.*)$")

PROMPT_CONNECTED = "Подключено. Команды: /help /users /active /quit · /clear — очистить экран"
PROMPT_GOODBYE = "Соединение закрыто."
PROMPT_LOST = "Связь с сервером потеряна."

def sanitize_one_line(text: str) -> str:
    """Убирает переводы строк — иначе протокол режет одно сообщение на части."""
    return " ".join(text.replace("\r", " ").replace("\n", " ").replace("\x0b", " ").split())

def _enable_utf8_console() -> None:
    if sys.platform != "win32":
        return
    for stream in (sys.stdin, sys.stdout, sys.stderr):
        try:
            stream.reconfigure(encoding="utf-8")  # type: ignore[attr-defined]
        except (AttributeError, OSError):
            pass

class LineProtocol:
    def __init__(self, sock: socket.socket) -> None:
        self._sock = sock
        self._buffer = ""

    def send_line(self, text: str) -> None:
        safe = sanitize_one_line(text)
        self._sock.sendall((safe + "\n").encode(ENCODING))

    def recv_line(self) -> str | None:
        while "\n" not in self._buffer:
            chunk = self._sock.recv(RECV_CHUNK)
            if not chunk:
                return None
            self._buffer += chunk.decode(ENCODING, errors="replace")
        line, self._buffer = self._buffer.split("\n", 1)
        return line.rstrip("\r")

class MsgKind(Enum):
    CHAT = auto()
    SYSTEM = auto()
    REPLY = auto()

def classify(text: str) -> MsgKind:
    if text.startswith(BLOCK_MAGIC):
        return MsgKind.REPLY
    if CHAT_RE.match(text):
        return MsgKind.CHAT
    if text.startswith(("📢", "🚪", "ℹ️", "⚠️", "👥", "📊", "❓")):
        return MsgKind.SYSTEM
    if text.startswith("📜") or (text.startswith("/") and " — " in text):
        return MsgKind.REPLY
    return MsgKind.REPLY

def format_line(text: str) -> str:
    if text.startswith(BLOCK_MAGIC):
        return text
    match = CHAT_RE.match(text)
    if match:
        return _format_chat_line(*match.groups())
    clean = sanitize_one_line(text)
    if len(clean) > DISPLAY_OTHER_MAX:
        clean = clean[: DISPLAY_OTHER_MAX - 1] + "…"
    return clean

def _format_chat_line(ts: str, nick: str, body: str) -> str:
    body = sanitize_one_line(body)
    if len(body) > DISPLAY_BODY_MAX:
        body = body[: DISPLAY_BODY_MAX - 1] + "…"
    header = f"[{ts}] {nick}: "
    if len(header) + len(body) <= TERMINAL_WIDTH:
        return header + body
    return textwrap.fill(
        body,
        width=TERMINAL_WIDTH,
        initial_indent=header,
        subsequent_indent=" " * len(header),
        break_long_words=True,
        break_on_hyphens=False,
    )

def normalize_outgoing(msg: str) -> str | None:
    """Нормализует ввод; None — не отправлять на сервер."""
    stripped = msg.strip()
    if not stripped:
        return None

    if stripped.startswith("/"):
        return stripped

    word = stripped.split(maxsplit=1)[0].casefold()
    typo = COMMAND_TYPOS.get(word)
    if typo:
        return typo

    if word in KNOWN_COMMANDS:
        return f"/{stripped}"

    return stripped

class ConsoleUI:
    def __init__(self, nick: str, stdout: TextIO) -> None:
        self._nick = nick
        self._out = stdout
        self._lock = threading.Lock()

    def update_nick(self, nick: str) -> None:
        self._nick = nick

    @property
    def nick(self) -> str:
        return self._nick

    def write_system(self, text: str) -> None:
        with self._lock:
            self._out.write(f"\n▸ {text}\n")
            self._out.flush()

    def write_incoming(self, text: str) -> None:
        with self._lock:
            self._out.write("\n")
            for part in text.splitlines():
                self._out.write(f"  {part}\n")
            self._out.flush()

    def write_help(self, lines: list[str]) -> None:
        with self._lock:
            self._out.write("\n┌─ справка ─────────────────\n")
            for line in lines:
                self._out.write(f"│ {line}\n")
            self._out.write("└──────────────────────────\n")
            self._out.flush()

    def write_fold_notice(self, count: int) -> None:
        with self._lock:
            self._out.write(f"\n  … похожих сообщений скрыто: {count}\n")
            self._out.flush()

class ChatFold:
    """Сворачивает одинаковые подряд сообщения чата в консоли."""

    def __init__(self) -> None:
        self._key: str | None = None
        self._hidden = 0

    def accept(self, fold_key: str) -> tuple[bool, int]:
        if fold_key == self._key:
            self._hidden += 1
            return False, 0

        suppressed = self._hidden
        self._key = fold_key
        self._hidden = 0
        return True, suppressed

    def flush(self) -> int:
        count = self._hidden
        self._hidden = 0
        self._key = None
        return count

def chat_fold_key(text: str) -> str:
    match = CHAT_RE.match(text)
    if not match:
        return text[:80]
    _ts, nick, body = match.groups()
    sample = body[:48]
    return f"{nick}|{sample}"

class ChatClient:
    def __init__(
        self,
        host: str,
        port: int,
        stdin: TextIO | None = None,
        stdout: TextIO | None = None,
    ) -> None:
        self.host = host
        self.port = port
        self._stdin = stdin or sys.stdin
        self._stdout = stdout or sys.stdout
        self._sock: socket.socket | None = None
        self._protocol: LineProtocol | None = None
        self._ui: ConsoleUI | None = None
        self._running = threading.Event()
        self._closed = False
        self._pending: str | None = None
        self._fold = ChatFold()
        self._orphan: str | None = None  # хвост сообщения, разорванного протоколом

    def connect(self, nick: str) -> None:
        nick = nick.strip()[:MAX_NICK_LEN] or "Аноним"
        clean = nick.replace("\n", "").replace("\r", "")
        self._ui = ConsoleUI(clean, self._stdout)

        self._sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self._sock.connect((self.host, self.port))
        self._protocol = LineProtocol(self._sock)
        self._protocol.send_line(clean)

        self._running.set()
        threading.Thread(target=self._receive_loop, name="receiver", daemon=True).start()

    def run(self) -> None:
        assert self._ui is not None and self._protocol is not None
        self._ui.write_system(PROMPT_CONNECTED)

        try:
            while self._running.is_set():
                try:
                    raw = input(f"{self._ui.nick}: ")
                except EOFError:
                    break

                outgoing = normalize_outgoing(raw)
                if outgoing is None:
                    continue

                if outgoing.casefold() in LOCAL_COMMANDS:
                    self._run_local(outgoing)
                    continue

                try:
                    self._protocol.send_line(outgoing)
                except OSError:
                    self._running.clear()
                    break

                if outgoing.casefold() in QUIT_COMMANDS:
                    break
        except KeyboardInterrupt:
            pass
        finally:
            self._flush_orphan()
            self._flush_fold()
            self.close()

    def _run_local(self, cmd: str) -> None:
        if cmd.casefold() == "/clear":
            os.system("cls" if os.name == "nt" else "clear")

    def close(self) -> None:
        if self._closed:
            return
        self._closed = True
        self._running.clear()

        if self._sock:
            try:
                self._sock.shutdown(socket.SHUT_RDWR)
            except OSError:
                pass
            try:
                self._sock.close()
            except OSError:
                pass
            self._sock = None

        if self._ui:
            self._ui.write_system(PROMPT_GOODBYE)

    def _receive_loop(self) -> None:
        assert self._protocol is not None and self._ui is not None

        while self._running.is_set():
            line = self._pending
            self._pending = None

            if line is None:
                try:
                    line = self._protocol.recv_line()
                except OSError:
                    break

            if line is None:
                self._flush_orphan()
                self._ui.write_system(PROMPT_LOST)
                break

            self._maybe_update_nick(line)

            if line.startswith(BLOCK_MAGIC):
                payload = line[len(BLOCK_MAGIC) :]
                lines = payload.split(BLOCK_SEP) if payload else []
                self._ui.write_help(lines)
                continue

            if line.startswith("📜") or (
                line.startswith("/") and " — " in line and not line.startswith("/quit")
            ):
                block = self._collect_legacy_help(line)
                self._ui.write_help(block)
                continue

            merged = self._merge_fragment(line)
            if merged is None:
                continue

            kind = classify(merged)
            if kind is MsgKind.CHAT:
                self._show_chat(merged)
            else:
                self._flush_fold()
                self._ui.write_incoming(format_line(merged))

        self._running.clear()

    def _is_structured(self, line: str) -> bool:
        return bool(
            CHAT_RE.match(line)
            or line.startswith(BLOCK_MAGIC)
            or line.startswith(("📢", "🚪", "ℹ️", "⚠️", "👥", "📊", "❓", "📜"))
            or (line.startswith("/") and " — " in line)
        )

    def _flush_orphan(self) -> None:
        if self._orphan and self._ui:
            self._ui.write_incoming(f"↳ {sanitize_one_line(self._orphan)}")
            self._orphan = None

    def _merge_fragment(self, line: str) -> str | None:
        """Обрывки без заголовка чата копятся и выводятся как продолжение."""
        if self._is_structured(line):
            self._flush_orphan()
            return line

        if self._orphan:
            self._orphan = f"{self._orphan} {line.lstrip()}"
        else:
            self._orphan = line
        return None

    def _show_chat(self, raw: str) -> None:
        assert self._ui is not None
        key = chat_fold_key(raw)
        show, suppressed = self._fold.accept(key)
        if suppressed > 0:
            self._ui.write_fold_notice(suppressed)
        if not show:
            return
        self._ui.write_incoming(format_line(raw))

    def _flush_fold(self) -> None:
        assert self._ui is not None
        hidden = self._fold.flush()
        if hidden > 0:
            self._ui.write_fold_notice(hidden)

    def _collect_legacy_help(self, first: str) -> list[str]:
        lines = [first]
        if not self._sock:
            return lines

        deadline = time.monotonic() + HELP_BURST_SEC
        old_timeout = self._sock.gettimeout()
        try:
            while time.monotonic() < deadline:
                self._sock.settimeout(max(0.01, deadline - time.monotonic()))
                try:
                    nxt = self._protocol.recv_line()  # type: ignore[union-attr]
                except socket.timeout:
                    break
                except OSError:
                    break
                if nxt is None:
                    break
                if not nxt.startswith("/") and not nxt.startswith("📜"):
                    self._pending = nxt
                    break
                lines.append(nxt)
        finally:
            try:
                self._sock.settimeout(old_timeout)
            except OSError:
                pass
        return lines

    def _maybe_update_nick(self, text: str) -> None:
        marker = "вы вошли как «"
        if marker not in text or not self._ui:
            return
        start = text.index(marker) + len(marker)
        end = text.find("»", start)
        if end != -1:
            self._ui.update_nick(text[start:end])

def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="TCP-чат (клиент)")
    parser.add_argument("--host", default=DEFAULT_HOST, help="Адрес сервера")
    parser.add_argument("--port", type=int, default=DEFAULT_PORT, help="Порт")
    parser.add_argument("-n", "--nick", help="Имя")
    return parser.parse_args()

def main() -> None:
    _enable_utf8_console()
    args = parse_args()
    try:
        nick = args.nick or input("👤 Ваше имя: ").strip()
    except KeyboardInterrupt:
        print()
        return

    client = ChatClient(host=args.host, port=args.port)
    try:
        client.connect(nick)
        client.run()
    except (ConnectionRefusedError, OSError) as exc:
        print(f"❌ Не удалось подключиться к {args.host}:{args.port}: {exc}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()
